 21→/// Direction(s) indicated by `..` notation.
 22→#[derive(Debug, Clone, PartialEq, Eq)]
 23→pub enum DotDirection {
 24→    /// No dots: just the revision itself.
 25→    None,
 26→    /// `x..` — ancestors (x at top, older below).
 27→    Ancestors,
 28→    /// `..x` — descendants (newer above, x at bottom).
 29→    Descendants,
 30→    /// `..x..` — both directions, x in the middle.
 31→    Both,
 32→}
 33→
 34→/// Result of parsing positional `..` notation.
 35→#[derive(Debug, Clone, PartialEq, Eq)]
 36→pub struct DotSpec {
 37→    /// The bare revision (without `..`).
 38→    pub rev: String,
 39→    /// Which direction(s) the dots indicate.
 40→    pub direction: DotDirection,
 41→    /// Count per dotted side (x is not counted).
 42→    pub count: usize,
 43→}
 44→
 45→/// Parse a positional REV string for `..` notation.
 46→///
 47→/// Returns the bare revision, direction, and default count (0).
 48→/// Count is set separately from the second positional arg.
 49→pub fn parse_dot_rev(rev: &str) -> DotSpec {
 50→    if let Some(inner) = rev.strip_prefix("..").and_then(|s| s.strip_suffix("..")) {
 51→        DotSpec {
 52→            rev: inner.to_string(),
 53→            direction: DotDirection::Both,
 54→            count: 0,
 55→        }
 56→    } else if let Some(inner) = rev.strip_prefix("..") {
 57→        DotSpec {
 58→            rev: inner.to_string(),
 59→            direction: DotDirection::Descendants,
 60→            count: 0,
 61→        }
 62→    } else if let Some(inner) = rev.strip_suffix("..") {
 63→        DotSpec {
 64→            rev: inner.to_string(),
 65→            direction: DotDirection::Ancestors,
 66→            count: 0,
 67→        }
 68→    } else {
 69→        DotSpec {
 70→            rev: rev.to_string(),
 71→            direction: DotDirection::None,
 72→            count: 0,
 73→        }
 74→    }
 75→}
 76→
 77→/// Resolve effective revision, limit, and whether results need reversing
 78→/// from positional args combined with named flags.
 79→///
 80→/// Named flags (`-r`, `-l`) take precedence over positional args.
 81→pub struct ResolvedArgs {
 82→    /// The jj revset string to evaluate.
 83→    pub revset: String,
 84→    /// Maximum number of commits to return (None = unlimited).
 85→    pub limit: Option<usize>,
 86→    /// For `..x..`, the count per side.
 87→    pub both_count: Option<usize>,
 88→    /// The bare primary revision (for highlighting).
 89→    pub primary_rev: String,
 90→}
 91→
 92→/// Resolve positional `..` args with named flag overrides.
 93→///
 94→/// - `pos_rev`: first positional arg (may contain `..`)
 95→/// - `pos_count`: second positional arg
 96→/// - `flag_rev`: `-r` flag value (if different from default)
 97→/// - `flag_limit`: `-l` flag value
 98→/// - `default_rev`: the default revision (e.g. "@")
 99→pub fn resolve_dot_args(
100→    pos_rev: Option<&str>,
101→    pos_count: Option<usize>,
102→    flag_rev: &str,
103→    flag_limit: Option<usize>,
104→    default_rev: &str,
105→) -> ResolvedArgs {
106→    // If named flags were explicitly set, they take full precedence
107→    let flag_rev_set = flag_rev != default_rev;
108→    let flag_limit_set = flag_limit.is_some();
109→
110→    if flag_rev_set || (flag_limit_set && pos_rev.is_none()) {
111→        return ResolvedArgs {
112→            revset: flag_rev.to_string(),
113→            limit: flag_limit,
114→            both_count: None,
115→            primary_rev: flag_rev.to_string(),
116→        };
117→    }
118→
119→    // Use positional args
120→    let rev_str = pos_rev.unwrap_or(default_rev);
121→    let mut spec = parse_dot_rev(rev_str);
122→
123→    // If there's a positional count, set it
124→    if let Some(c) = pos_count {
125→        spec.count = c;
126→    }
127→
128→    // Named limit overrides positional count
129→    if flag_limit_set {
130→        spec.count = flag_limit.unwrap();
131→    }
132→
133→    let primary = spec.rev.clone();
134→
135→    match spec.direction {
136→        DotDirection::None => {
137→            if spec.count > 0 {
138→                // bare `x 5` → `x.. 5` (ancestors)
139→                ResolvedArgs {
140→                    revset: format!("::{}", spec.rev),
141→                    limit: Some(spec.count + 1), // +1 for x itself
142→                    both_count: None,
143→                    primary_rev: primary,
144→                }
145→            } else {
146→                ResolvedArgs {
147→                    revset: spec.rev,
148→                    limit: Some(1),
149→                    both_count: None,
150→                    primary_rev: primary,
151→                }
152→            }
153→        }
154→        DotDirection::Ancestors => {
155→            if spec.count > 0 {
156→                ResolvedArgs {
157→                    revset: format!("::{}", spec.rev),
158→                    limit: Some(spec.count + 1),
159→                    both_count: None,
160→                    primary_rev: primary,
161→                }
162→            } else {
163→                ResolvedArgs {
164→                    revset: format!("::{}", spec.rev),
165→                    limit: None,
166→                    both_count: None,
167→                    primary_rev: primary,
168→                }
169→            }
170→        }
171→        DotDirection::Descendants => {
172→            if spec.count > 0 {
173→                ResolvedArgs {
174→                    revset: format!("{}::", spec.rev),
175→                    limit: Some(spec.count + 1),
176→                    both_count: None,
177→                    primary_rev: primary,
178→                }
179→            } else {
180→                ResolvedArgs {
181→                    revset: format!("{}::", spec.rev),
182→                    limit: None,
183→                    both_count: None,
184→                    primary_rev: primary,
185→                }
186→            }
187→        }
188→        DotDirection::Both => ResolvedArgs {
189→            revset: format!("::{}|{}::", spec.rev, spec.rev),
190→            limit: None,
191→            both_count: Some(spec.count),
192→            primary_rev: primary,
193→        },
194→    }
195→}
