240→/// Format: changeID commitID first-line (single line).
241→pub fn format_commit_short(commit: &Commit) -> String {
242→    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
243→    let change_short = &change_hex[..change_hex.len().min(12)];
244→    let commit_hex = commit.id().hex();
245→    let commit_short = &commit_hex[..commit_hex.len().min(12)];
246→    let first_line = commit.description().lines().next().unwrap_or("");
247→    if first_line.is_empty() {
248→        format!("{change_short} {commit_short} (no description set)")
249→    } else {
250→        format!("{change_short} {commit_short} {first_line}")
251→    }
252→}
253→
254→/// Format: changeID commitID first-line, then remaining description lines.
255→pub fn format_commit_full(commit: &Commit) -> String {
256→    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
257→    let change_short = &change_hex[..change_hex.len().min(12)];
258→    let commit_hex = commit.id().hex();
259→    let commit_short = &commit_hex[..commit_hex.len().min(12)];
260→    let desc = commit.description();
261→    if desc.is_empty() {
262→        format!("{change_short} {commit_short} (no description set)")
263→    } else {
264→        let mut lines = desc.lines();
265→        let first_line = lines.next().unwrap_or("");
266→        let mut result = format!("{change_short} {commit_short} {first_line}");
267→        for line in lines {
268→            result.push('\n');
269→            result.push_str(line);
270→        }
271→        result
272→    }
273→}
