  9→pub struct ListArgs {
 10→    /// Revision (with optional .. notation)
 11→    #[arg()]
 12→    pub pos_rev: Option<String>,
 13→
 14→    /// Count (items per dotted side)
 15→    #[arg()]
 16→    pub pos_count: Option<usize>,
 17→
 18→    /// Revision to list (default: @)
 19→    #[arg(short, long, default_value = "@")]
 20→    pub revision: String,
 21→
 22→    /// Path to jj repo (default: current directory)
 23→    #[arg(short = 'R', long, default_value = ".")]
 24→    pub repo: PathBuf,
 25→
 26→    /// Maximum number of commits to show
 27→    #[arg(short, long)]
 28→    pub limit: Option<usize>,
 29→}
 30→
 31→pub fn list(args: &ListArgs) -> Result<(), Box<dyn std::error::Error>> {
 32→    let resolved = common::resolve_dot_args(
 33→        args.pos_rev.as_deref(),
 34→        args.pos_count,
 35→        &args.revision,
 36→        args.limit,
 37→        "@",
 38→    );
 39→
 40→    let (workspace, repo) = common::load_repo(&args.repo)?;
 41→
 42→    let commit_ids = common::resolve_revset(&workspace, &repo, &resolved.revset)?;
 43→
 44→    if commit_ids.is_empty() {
 45→        return Err(format!("no commit found for revision '{}'", resolved.revset).into());
 46→    }
 47→
 48→    let root_commit_id = repo.store().root_commit_id().clone();
 49→
 50→    if let Some(both_count) = resolved.both_count {
 51→        let (lines, anchor) = common::collect_both(
 52→            &repo,
 53→            &args.repo,
 54→            args.pos_rev.as_deref(),
 55→            both_count,
 56→            common::format_commit_short,
 57→        )?;
 58→        for (i, line) in lines.iter().enumerate() {
 59→            if i == anchor {
 60→                println!("{}", common::bold(line));
 61→            } else {
 62→                println!("{line}");
 63→            }
 64→        }
 65→        return Ok(());
 66→    }
 67→
 68→    // Resolve the primary commit ID for highlighting
 69→    let primary_ids = common::resolve_revset(&workspace, &repo, &resolved.primary_rev)?;
 70→    let primary_id = primary_ids.first();
 71→
 72→    let mut results: Vec<(String, bool)> = Vec::new();
 73→    let mut count = 0;
 74→    for commit_id in &commit_ids {
 75→        if *commit_id == root_commit_id {
 76→            continue;
 77→        }
 78→        let commit = repo.store().get_commit(commit_id)?;
 79→        let is_primary = primary_id == Some(commit_id);
 80→        results.push((common::format_commit_short(&commit), is_primary));
 81→
 82→        count += 1;
 83→        if let Some(limit) = resolved.limit
 84→            && count >= limit
 85→        {
 86→            break;
 87→        }
 88→    }
 89→
 90→    for (line, is_primary) in &results {
 91→        if *is_primary {
 92→            println!("{}", common::bold(line));
 93→        } else {
 94→            println!("{line}");
 95→        }
 96→    }
 97→
 98→    Ok(())
 99→}
