110→    pub async fn parents(&self) -> BackendResult<Vec<Self>> {
111→        try_join_all(
112→            self.data
113→                .parents
114→                .iter()
115→                .map(|id| self.store.get_commit_async(id)),
116→        )
117→        .await
118→    }
