 80→impl Operation {
 81→    pub fn new(
 82→        op_store: Arc<dyn OpStore>,
 83→        id: OperationId,
 84→        data: impl Into<Arc<op_store::Operation>>,
 85→    ) -> Self {
 86→        Self {
 87→            op_store,
 88→            id,
 89→            data: data.into(),
 90→        }
 91→    }
