126→    /// Returns true if predecessors are recorded in this operation.
127→    ///
128→    /// This returns false only if the operation was written by jj < 0.30.
129→    pub fn stores_commit_predecessors(&self) -> bool {
130→        self.data.commit_predecessors.is_some()
131→    }
