133→    /// Returns predecessors of the specified commit if recorded.
134→    pub fn predecessors_for_commit(&self, commit_id: &CommitId) -> Option<&[CommitId]> {
135→        let map = self.data.commit_predecessors.as_ref()?;
136→        Some(map.get(commit_id)?)
137→    }
138→
139→    /// Iterates all commit ids referenced by this operation ignoring the view.
140→    ///
141→    /// Use this in addition to [`View::all_referenced_commit_ids()`] to build
142→    /// commit index from scratch. The predecessor commit ids are also included,
143→    /// which ensures that the old commits to be returned by
144→    /// [`Self::predecessors_for_commit()`] are still reachable.
145→    ///
146→    /// The iteration order is unspecified.
147→    pub fn all_referenced_commit_ids(&self) -> impl Iterator<Item = &CommitId> {
148→        self.data.commit_predecessors.iter().flat_map(|map| {
149→            map.iter()
150→                .flat_map(|(new_id, old_ids)| iter::once(new_id).chain(old_ids))
151→        })
152→    }
153→
154→    pub fn store_operation(&self) -> &op_store::Operation {
155→        &self.data
156→    }
157→}
