 77→impl dyn OpHeadsStore {
 78→    /// Returns reference of the implementation type.
 79→    pub fn downcast_ref<T: OpHeadsStore>(&self) -> Option<&T> {
 80→        (self as &dyn Any).downcast_ref()
 81→    }
 82→}
